// Chinese (zh) + Vietnamese (vi) translations for product intro, feature
// bullets and application bullets, keyed by catalog slug. Originally generated
// from the client-supplied per-brand product JSON (data/i18n/products/*.json);
// products missing from that JSON are translated from the English catalog copy.
// Full spec tables are preserved in those JSON files for a later grouped-spec
// upgrade.

export type LocalizedText = { en: string; zh: string; vi: string };
export type LocalizedList = { en: string[]; zh: string[]; vi: string[] };
export type ProductI18n = { intro?: LocalizedText; features?: LocalizedList; applications?: LocalizedList };

export const productI18n: Record<string, ProductI18n> = {
  "ac2": { applications: {"en": ["UV curing of inks, adhesives, and coatings in small-area applications", "Electronics and optoelectronics component bonding", "Medical device small-area UV curing", "Low- to high-power small-area curing (curing widths ≤75 mm)"], "zh": ["小面积应用中油墨、胶水与涂层的UV固化", "电子与光电元件粘接", "医疗器械小面积UV固化", "低功率到高功率的小面积固化（固化宽度≤75毫米）"], "vi": ["Đóng rắn UV mực, keo và sơn phủ trong ứng dụng diện tích nhỏ", "Liên kết linh kiện điện tử và quang điện tử", "Đóng rắn UV diện tích nhỏ cho thiết bị y tế", "Đóng rắn diện tích nhỏ từ công suất thấp đến cao (chiều rộng đóng rắn ≤75 mm)"]}, intro: {"en": "The AC275 and AC2110 air-cooled UV LED curing systems are compact and ideal for applications with space constraints, designed with advanced front-end optics to provide high peak irradiance and exceptional uniformity. Suited for printing, medical device, electronic and optoelectronic applications.", "zh": "AC275与AC2110风冷式UV LED固化系统结构紧凑，适合空间受限的应用场景，配备先进前端光学设计，实现高峰值辐照度与卓越的均匀性。适用于印刷、医疗器械、电子与光电等领域。", "vi": "Hệ thống đóng rắn UV LED làm mát bằng khí AC275 và AC2110 có thiết kế nhỏ gọn, lý tưởng cho các ứng dụng hạn chế không gian, sử dụng quang học mặt trước tiên tiến để đạt độ rọi đỉnh cao và độ đồng đều vượt trội. Phù hợp cho ứng dụng in ấn, thiết bị y tế, điện tử và quang điện tử."}, features: {"en": ["Compact form factor ideal for space-constrained installations", "Advanced front-end optics for high peak irradiance and uniformity"], "zh": ["结构紧凑，适合空间受限的安装环境", "先进前端光学设计，实现高峰值辐照度与均匀性"], "vi": ["Kích thước nhỏ gọn, lý tưởng cho lắp đặt hạn chế không gian", "Quang học mặt trước tiên tiến cho độ rọi đỉnh cao và độ đồng đều"]} },
  "ac4": { applications: {"en": ["Small-area UV adhesive curing requiring high irradiance", "Electronic component bonding requiring precision and repeatability", "Medical device assembly", "UV curing at long working distances"], "zh": ["需要高辐照度的小面积UV胶水固化", "要求精密与可重复性的电子元件粘接", "医疗器械组装", "长工作距离下的UV固化"], "vi": ["Đóng rắn keo UV diện tích nhỏ cần độ rọi cao", "Liên kết linh kiện điện tử yêu cầu chính xác và lặp lại", "Lắp ráp thiết bị y tế", "Đóng rắn UV ở khoảng cách làm việc xa"]}, intro: {"en": "The AC450/P and AC475/P air-cooled UV LED small area curing systems provide high irradiance (8 W/cm2) at flexible working distances, ideal for medical device assembly and electronic applications requiring high throughput, low temperature curing.", "zh": "AC450/P与AC475/P风冷式UV LED小面积固化系统在灵活工作距离下提供高辐照度（8 W/cm²），适用于需要高产能、低温固化的医疗器械组装与电子应用。", "vi": "Hệ thống đóng rắn UV LED diện tích nhỏ làm mát bằng khí AC450/P và AC475/P cung cấp độ rọi cao (8 W/cm²) ở khoảng cách làm việc linh hoạt, lý tưởng cho lắp ráp thiết bị y tế và ứng dụng điện tử cần đóng rắn năng suất cao, nhiệt độ thấp."}, features: {"en": ["High irradiance of 8 W/cm2 at flexible working distances", "Suitable for high-throughput, low-temperature curing of plastic parts"], "zh": ["灵活工作距离下提供8 W/cm²高辐照度", "适用于塑料零件的高产能、低温固化"], "vi": ["Độ rọi cao 8 W/cm² ở khoảng cách làm việc linh hoạt", "Phù hợp đóng rắn năng suất cao, nhiệt độ thấp cho linh kiện nhựa"]} },
  "ac5": { applications: {"en": ["Small-area UV curing requiring 14 W/cm² irradiance", "Electronic and optoelectronic component assembly", "Medical device bonding and sealing", "Applications requiring precise UV dose control and power measurement"], "zh": ["需要14 W/cm²辐照度的小面积UV固化", "电子与光电元件组装", "医疗器械粘接与密封", "需要精准UV剂量控制与功率测量的应用"], "vi": ["Đóng rắn UV diện tích nhỏ cần độ rọi 14 W/cm²", "Lắp ráp linh kiện điện tử và quang điện tử", "Liên kết và làm kín thiết bị y tế", "Ứng dụng cần kiểm soát liều UV chính xác và đo công suất quang"]}, intro: {"en": "Designed with a unique combination of high output LEDs and custom optics delivering up to 14 W/cm2, the AC5 air-cooled UV LED system provides high irradiance at flexible working distances. The compact head design eliminates the need for external cooling or ozone extraction, simplifying integration, and can be mounted in any orientation.", "zh": "AC5风冷式UV LED系统采用高输出LED与定制光学设计的独特组合，最高可达14 W/cm²辐照度，并在灵活工作距离下提供高辐照度。紧凑灯头设计无需外部冷却或臭氧排放装置，大幅简化集成难度，且可任意方向安装。", "vi": "Hệ thống UV LED làm mát bằng khí AC5 được thiết kế với sự kết hợp độc đáo giữa LED công suất cao và quang học tùy chỉnh, đạt tới 14 W/cm², cung cấp độ rọi cao ở khoảng cách làm việc linh hoạt. Thiết kế đầu nhỏ gọn loại bỏ nhu cầu làm mát ngoài hoặc hút khí ozone, đơn giản hóa tích hợp, và có thể lắp đặt theo mọi hướng."}, features: {"en": ["Up to 14-15 W/cm2 peak irradiance", "No external cooling or ozone extraction needed; mountable in any orientation"], "zh": ["峰值辐照度最高达14-15 W/cm²", "无需外部冷却或臭氧排放装置，可任意方向安装"], "vi": ["Độ rọi đỉnh lên đến 14-15 W/cm²", "Không cần làm mát ngoài hay hút ozone; lắp đặt theo mọi hướng"]} },
  "ac7": { applications: {"en": ["Display and touch panel adhesive curing", "Thin film UV coating curing", "Fiber and optical component curing", "Large-area UV adhesive bonding in electronics manufacturing", "Applications requiring high irradiance at long working distances"], "zh": ["显示屏与触摸屏胶水固化", "薄膜UV涂层固化", "光纤与光学元件固化", "电子制造中的大面积UV胶粘接", "需要长工作距离下高辐照度的应用"], "vi": ["Đóng rắn keo màn hình và tấm cảm ứng", "Đóng rắn lớp phủ UV màng mỏng", "Đóng rắn sợi quang và linh kiện quang học", "Liên kết keo UV diện tích lớn trong sản xuất điện tử", "Ứng dụng cần độ rọi cao ở khoảng cách làm việc xa"]}, intro: {"en": "The AC7150 and AC7300 provide exceptional uniformity over the full curing area for even and consistent curing. Multiple systems can be joined together without compromising uniformity, for greater flexibility in curing larger parts. Designed for medical device, electronic assembly, automotive, optical fiber, and industrial applications.", "zh": "AC7150与AC7300在整个固化区域内提供卓越的均匀性，实现均衡一致的固化效果，且可多台联接组合而不影响均匀性，适用于更大尺寸零件的固化需求。适用于医疗器械、电子组装、汽车、光纤及工业应用领域。", "vi": "AC7150 và AC7300 cung cấp độ đồng đều vượt trội trên toàn bộ vùng đóng rắn để đóng rắn đều và nhất quán. Nhiều hệ thống có thể ghép nối mà không ảnh hưởng độ đồng đều, mang lại tính linh hoạt cao hơn khi đóng rắn các bộ phận lớn hơn. Thiết kế cho lắp ráp thiết bị y tế, điện tử, ô tô, sợi quang và ứng dụng công nghiệp."}, features: {"en": ["Exceptional uniformity over full curing area", "Multiple systems can be joined for wider curing without uniformity loss"], "zh": ["整个固化区域内均匀性卓越", "可多台联接以扩大固化宽度，且不影响均匀性"], "vi": ["Độ đồng đều vượt trội trên toàn vùng đóng rắn", "Có thể ghép nhiều hệ thống để mở rộng vùng đóng rắn mà không mất độ đồng đều"]} },
  "ac8": { applications: {"en": ["Display, touch panel and thin film adhesive/coating curing", "Print applications requiring short working distance dose optimization ('P' models)", "Large-area UV curing on electronics and optics production lines", "Industrial adhesive and coating curing requiring >8 W/cm² irradiance", "Applications requiring scalable curing width without uniformity compromise"], "zh": ["显示屏、触摸屏与薄膜的胶水/涂层固化", "需要短工作距离剂量优化的印刷应用（\"P\"型号）", "电子与光学生产线上的大面积UV固化", "需要>8 W/cm²辐照度的工业胶水与涂层固化", "需要在不影响均匀性的前提下扩展固化宽度的应用"], "vi": ["Đóng rắn keo/lớp phủ màn hình, tấm cảm ứng và màng mỏng", "Ứng dụng in cần tối ưu liều ở khoảng cách làm việc ngắn (model \"P\")", "Đóng rắn UV diện tích lớn trên dây chuyền điện tử và quang học", "Đóng rắn keo và sơn phủ công nghiệp cần độ rọi >8 W/cm²", "Ứng dụng cần mở rộng chiều rộng đóng rắn mà không giảm độ đồng đều"]}, intro: {"en": "The AC8150/P, AC8225/P and AC8300/P air-cooled UV LED curing systems deliver over 8 W/cm2 peak irradiance for fast, even curing at long working distances. \"P\" versions feature enhanced optics optimized for short working distances required by print applications.", "zh": "AC8150/P、AC8225/P与AC8300/P风冷式UV LED固化系统峰值辐照度超过8 W/cm²，在长工作距离下实现快速均匀固化。\"P\"版本配备增强光学设计，专为印刷应用所需的短工作距离优化。", "vi": "Hệ thống đóng rắn UV LED làm mát bằng khí AC8150/P, AC8225/P và AC8300/P đạt độ rọi đỉnh trên 8 W/cm², đóng rắn nhanh và đều ở khoảng cách làm việc xa. Phiên bản \"P\" có quang học tăng cường tối ưu cho khoảng cách làm việc ngắn cần thiết trong ứng dụng in ấn."}, features: {"en": ["Over 8 W/cm2 peak irradiance for fast, even curing at long working distances", "\"P\" print versions optimized for short working distances"], "zh": ["峰值辐照度超过8 W/cm²，长工作距离下实现快速均匀固化", "\"P\"印刷版本针对短工作距离优化"], "vi": ["Độ rọi đỉnh trên 8 W/cm², đóng rắn nhanh đều ở khoảng cách xa", "Phiên bản in \"P\" tối ưu cho khoảng cách làm việc ngắn"]} },
  "ac8-hd": { applications: {"en": ["Large-area UV curing demanding the highest optical dose", "Display, touch panel, thin film bonding and coating requiring double-dose performance", "Electronics UV adhesive curing where standard AC8 dose is insufficient", "Applications requiring tight process control with customizable UV LED output", "High-speed production lines requiring maximum UV output in a compact footprint"], "zh": ["要求最高光学剂量的大面积UV固化", "需要双倍剂量性能的显示屏、触摸屏、薄膜粘接与涂层", "标准AC8剂量不足时的电子UV胶水固化", "需要可定制UV LED输出与严格过程控制的应用", "需要在紧凑空间内实现最大UV输出的高速生产线"], "vi": ["Đóng rắn UV diện tích lớn đòi hỏi liều quang cao nhất", "Liên kết và phủ màn hình, tấm cảm ứng, màng mỏng cần hiệu suất liều gấp đôi", "Đóng rắn keo UV điện tử khi liều AC8 tiêu chuẩn không đủ", "Ứng dụng cần kiểm soát quy trình chặt chẽ với đầu ra UV LED tùy chỉnh", "Dây chuyền tốc độ cao cần đầu ra UV tối đa trong không gian nhỏ gọn"]}, intro: {"en": "The AC8-HD Series brings air-cooled UV LED curing to the next level, delivering over 15 W/cm2 peak irradiance and nearly double the dose of the AC8 Series, with innovative technology enabling unbeatable uniformity across the irradiation area. Offers three standard cure widths (6\", 9\", 12\") that can be adjoined for customized curing sizes.", "zh": "AC8-HD系列将风冷式UV LED固化技术推向新高度，峰值辐照度超过15 W/cm²，剂量几乎是AC8系列的两倍，并通过创新技术实现整个照射区域内无可匹敌的均匀性。提供三种标准固化宽度（6英寸、9英寸、12英寸），可拼接组合以定制固化尺寸。", "vi": "Dòng AC8-HD đưa công nghệ đóng rắn UV LED làm mát bằng khí lên một tầm cao mới, đạt độ rọi đỉnh trên 15 W/cm² và liều gần gấp đôi dòng AC8, với công nghệ đột phá mang lại độ đồng đều vượt trội trên toàn vùng chiếu xạ. Có ba độ rộng đóng rắn tiêu chuẩn (6\", 9\", 12\") có thể ghép nối để tùy chỉnh kích thước đóng rắn."}, features: {"en": ["Over 15 W/cm2 peak irradiance, nearly double the dose of AC8 Series", "Three standard cure widths adjoinable for customized sizes"], "zh": ["峰值辐照度超过15 W/cm²，剂量近乎AC8系列的两倍", "三种标准固化宽度，可拼接定制尺寸"], "vi": ["Độ rọi đỉnh trên 15 W/cm², liều gần gấp đôi dòng AC8", "Ba độ rộng đóng rắn tiêu chuẩn, có thể ghép nối tùy chỉnh kích thước"]} },
  "ac9225": { applications: {"en": ["High-speed UV ink curing requiring >14 W/cm² irradiance", "Adhesive and coating curing on electronics and display production lines", "Print applications requiring high-power UV output over 225 mm width", "Industrial manufacturing requiring best-in-class air-cooled UV LED performance", "Applications scaling from AC8225 needing higher irradiance in the same footprint"], "zh": ["需要>14 W/cm²辐照度的高速UV油墨固化", "电子与显示屏生产线上的胶水与涂层固化", "需要225毫米宽度高功率UV输出的印刷应用", "需要一流风冷UV LED性能的工业制造", "从AC8225升级、需要在相同空间内获得更高辐照度的应用"], "vi": ["Đóng rắn mực UV tốc độ cao cần độ rọi >14 W/cm²", "Đóng rắn keo và sơn phủ trên dây chuyền điện tử và màn hình", "Ứng dụng in cần đầu ra UV công suất cao trên chiều rộng 225 mm", "Sản xuất công nghiệp cần hiệu suất UV LED làm mát bằng khí hàng đầu", "Ứng dụng nâng cấp từ AC8225 cần độ rọi cao hơn trong cùng không gian"]}, intro: {"en": "The AC9 Series are high-power UV LED curing systems delivering over 14 W/cm2 peak irradiance for fast curing of inks, adhesives and coatings. Innovative design features a high-performing, small form-factor air-cooled solution enabling fast line speeds. Individual LED module control provides exceptional uniformity, and the scalable design allows multiple heads to be adjoined.", "zh": "AC9系列是高功率UV LED固化系统，峰值辐照度超过14 W/cm²，可快速固化油墨、胶水与涂层。创新设计采用高性能小尺寸风冷方案，可实现高速生产线运行。独立LED模块控制带来卓越均匀性，可扩展设计支持多个灯头拼接组合。", "vi": "Dòng AC9 là hệ thống đóng rắn UV LED công suất cao, đạt độ rọi đỉnh trên 14 W/cm² để đóng rắn nhanh mực in, keo dán và sơn phủ. Thiết kế đột phá với giải pháp làm mát bằng khí hiệu suất cao, kích thước nhỏ gọn, cho phép tốc độ dây chuyền nhanh. Điều khiển từng mô-đun LED riêng lẻ mang lại độ đồng đều vượt trội, thiết kế mở rộng cho phép ghép nối nhiều đầu."}, features: {"en": ["Over 14 W/cm2 peak irradiance for fast curing", "Individual LED module control for exceptional curing uniformity", "Scalable design — multiple heads can be adjoined"], "zh": ["峰值辐照度超过14 W/cm²，实现快速固化", "独立LED模块控制，实现卓越固化均匀性", "可扩展设计，支持多个灯头拼接组合"], "vi": ["Độ rọi đỉnh trên 14 W/cm² để đóng rắn nhanh", "Điều khiển mô-đun LED riêng lẻ cho độ đồng đều đóng rắn vượt trội", "Thiết kế mở rộng — có thể ghép nối nhiều đầu"]} },
  "ac9225-f": { applications: {"en": ["Optical fiber coating cure", "High-speed fiber production lines", "Fiber draw, coloring and marking processes", "Upgrades from arc-lamp fiber curing seeking higher line speeds"], "zh": ["光纤涂层固化", "高速光纤生产线", "光纤拉丝、着色与标识工艺", "从电弧灯光纤固化升级、追求更高线速的应用"], "vi": ["Đóng rắn lớp phủ sợi quang", "Dây chuyền sản xuất sợi quang tốc độ cao", "Quy trình kéo sợi, nhuộm màu và đánh dấu sợi quang", "Nâng cấp từ đóng rắn sợi bằng đèn hồ quang để đạt tốc độ dây chuyền cao hơn"]}, intro: {"en": "Specifically designed for fiber curing applications, the AC9225-F delivers up to 88 W/cm2 peak irradiance at the fiber in typical face-to-face configuration, with 10-18mm working distance. Reduces electrical power consumption by up to 60% compared to traditional arc lamp systems, with over 40,000 hours of LED lifetime and no replacement parts.", "zh": "AC9225-F专为光纤固化应用设计，在典型面对面配置下可实现高达88 W/cm²的峰值辐照度，工作距离为10-18毫米。相较传统电弧灯系统，可节省高达60%的电力消耗，LED寿命超过40,000小时，无需更换部件。", "vi": "Được thiết kế riêng cho ứng dụng đóng rắn sợi quang, AC9225-F đạt độ rọi đỉnh lên đến 88 W/cm² tại sợi quang trong cấu hình đối diện điển hình, khoảng cách làm việc 10-18mm. Giảm tiêu thụ điện lên đến 60% so với hệ thống đèn hồ quang truyền thống, tuổi thọ LED trên 40.000 giờ và không cần thay thế linh kiện."}, features: {"en": ["Up to 88 W/cm2 peak irradiance at the fiber", "Reduces power consumption by up to 60% vs. arc lamp systems", "Over 40,000 hours LED lifetime with no replacement parts"], "zh": ["光纤处峰值辐照度高达88 W/cm²", "相较电弧灯系统，节省高达60%电力消耗", "LED寿命超过40,000小时，无需更换部件"], "vi": ["Độ rọi đỉnh tại sợi quang lên đến 88 W/cm²", "Giảm tiêu thụ điện đến 60% so với hệ thống đèn hồ quang", "Tuổi thọ LED trên 40.000 giờ, không cần thay thế linh kiện"]} },
  "f-series": { applications: {"en": ["Industrial UV curing of adhesives, coatings, and inks", "Optical fiber coating curing", "Wire and cable coating and marking", "Printing and converting applications", "Electronics and medical device UV adhesive curing"], "zh": ["胶水、涂层与油墨的工业UV固化", "光纤涂层固化", "电线电缆涂层与标识", "印刷与加工转换应用", "电子与医疗器械UV胶水固化"], "vi": ["Đóng rắn UV công nghiệp cho keo, sơn phủ và mực", "Đóng rắn lớp phủ sợi quang", "Phủ và đánh dấu dây điện, cáp", "Ứng dụng in và gia công chuyển đổi", "Đóng rắn keo UV cho điện tử và thiết bị y tế"]}, intro: {"en": "An economical electrodeless UV lamp system offering unlimited cure width by stacking lamps end-to-end. Features a semi-elliptical reflector geometry, optional dichroic reflectors, and optional mechanical shutter, suitable for a broad range of standard industrial UV curing applications.", "zh": "经济型无极UV灯系统，可通过首尾拼接灯具实现无限固化宽度。采用半椭圆反射器几何设计，可选配二向色反射器与机械快门，适用于各类标准工业UV固化应用。", "vi": "Hệ thống đèn UV không điện cực kinh tế, cho phép độ rộng đóng rắn không giới hạn bằng cách ghép nối các đèn nối tiếp. Có hình học gương phản xạ bán elip, gương phản xạ lưỡng sắc tùy chọn, và cửa chớp cơ học tùy chọn, phù hợp cho nhiều ứng dụng đóng rắn UV công nghiệp tiêu chuẩn."}, features: {"en": ["Unlimited cure width by stacking lamps end-to-end", "Fast startup: 20s cold start, 5s warm start (F300S/F300SQ)", "Standard external control and remote cooling blower"], "zh": ["灯具可首尾拼接，实现无限固化宽度", "启动迅速：冷启动20秒，热启动5秒（F300S/F300SQ）", "标配外部控制与远程冷却风机"], "vi": ["Độ rộng đóng rắn không giới hạn bằng ghép nối đèn nối tiếp", "Khởi động nhanh: khởi động nguội 20s, khởi động nóng 5s (F300S/F300SQ)", "Điều khiển ngoài tiêu chuẩn và quạt làm mát từ xa"]} },
  "fe100": { applications: {"en": ["Digital inkjet printing (pinning & full cure)", "Adhesives", "Coatings", "Flat panel display edge curing", "Space-constrained inline installations"], "zh": ["数码喷墨印刷（点固化与完全固化）", "胶水固化", "涂层固化", "平板显示器边缘固化", "空间受限的在线安装场景"], "vi": ["In phun kỹ thuật số (định hình & đóng rắn hoàn toàn)", "Keo dán", "Sơn phủ", "Đóng rắn cạnh màn hình phẳng", "Lắp đặt nội tuyến hạn chế không gian"]}, intro: {"en": "A natural convection-cooled UV LED system with WhisperCure technology, a thin form factor, and analog control, designed for pinning and gelling applications.", "zh": "采用自然对流冷却的UV LED系统，搭载WhisperCure技术，机身轻薄，支持模拟控制，专为点固化与凝胶化应用设计。", "vi": "Hệ thống UV LED làm mát bằng đối lưu tự nhiên với công nghệ WhisperCure, kích thước mỏng, và điều khiển tương tự, được thiết kế cho ứng dụng định hình và đông gel."}, features: {"en": ["Natural convection cooling, no fan required", "Thin form factor designed for pinning and gelling"], "zh": ["自然对流冷却，无需风扇", "机身轻薄，专为点固化与凝胶化设计"], "vi": ["Làm mát đối lưu tự nhiên, không cần quạt", "Kích thước mỏng, thiết kế cho định hình và đông gel"]} },
  "fe410": { applications: {"en": ["Digital inkjet printing — UV pinning and full cure", "3D printing UV curing at higher throughput", "UV adhesive curing in electronics and medical assembly", "Production lines upgrading from FE400 seeking enhanced throughput"], "zh": ["数码喷墨印刷——UV点固化与完全固化", "更高产能的3D打印UV固化", "电子与医疗组装中的UV胶水固化", "从FE400升级、追求更高产能的生产线"], "vi": ["In phun kỹ thuật số — định hình UV và đóng rắn hoàn toàn", "Đóng rắn UV trong in 3D với năng suất cao hơn", "Đóng rắn keo UV trong lắp ráp điện tử và y tế", "Dây chuyền nâng cấp từ FE400 để tăng năng suất"]}, intro: {"en": "An air-cooled UV LED system with TargetCure and WhisperCure technology delivering full cure, optics options, analog control, and a small form factor.", "zh": "风冷式UV LED系统，搭载TargetCure与WhisperCure技术，实现完全固化，提供光学选配方案，支持模拟控制，体积小巧。", "vi": "Hệ thống UV LED làm mát bằng khí với công nghệ TargetCure và WhisperCure mang lại đóng rắn hoàn toàn, tùy chọn quang học, điều khiển tương tự, và kích thước nhỏ gọn."}, features: {"en": ["Full cure with TargetCure and WhisperCure technology", "Optics options available, small form factor"], "zh": ["搭载TargetCure与WhisperCure技术，实现完全固化", "提供光学选配方案，体积小巧"], "vi": ["Đóng rắn hoàn toàn với công nghệ TargetCure và WhisperCure", "Có tùy chọn quang học, kích thước nhỏ gọn"]} },
  "firejet-one": { applications: {"en": ["UV curing of inks, coatings and adhesives", "Digital and industrial printing", "Web and conveyor-based production lines", "Large-area curing requiring high power in a compact footprint"], "zh": ["油墨、涂层与胶水的UV固化", "数码与工业印刷", "卷筒与传送带式生产线", "需要紧凑空间内高功率的大面积固化"], "vi": ["Đóng rắn UV cho mực, sơn phủ và keo dán", "In kỹ thuật số và công nghiệp", "Dây chuyền dạng cuộn và băng tải", "Đóng rắn diện tích lớn cần công suất cao trong không gian nhỏ gọn"]}, intro: {"en": "An air-cooled UV LED system with TargetCure and WhisperCure technology, offering high irradiance in a small, scalable form factor with optional Ethernet communication.", "zh": "风冷式UV LED系统，搭载TargetCure与WhisperCure技术，体积小巧、可扩展，提供高辐照度，并支持可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng khí với công nghệ TargetCure và WhisperCure, mang lại độ rọi cao trong kích thước nhỏ gọn, có thể mở rộng, với giao tiếp Ethernet tùy chọn."}, features: {"en": ["TargetCure and WhisperCure technology", "High irradiance in a small, scalable form factor"], "zh": ["搭载TargetCure与WhisperCure技术", "体积小巧可扩展，辐照度高"], "vi": ["Công nghệ TargetCure và WhisperCure", "Độ rọi cao trong kích thước nhỏ gọn, có thể mở rộng"]} },
  "fj100": { applications: {"en": ["UV inkjet printing (primary application)", "Coating curing on printing presses and coaters", "PCB silkscreen and solder mask printing", "Space-constrained environments requiring high-intensity UV curing", "Industrial printing requiring scalable UV curing width"], "zh": ["UV喷墨印刷（主要应用）", "印刷机与涂布机上的涂层固化", "PCB丝印与阻焊印刷", "需要高强度UV固化的空间受限环境", "需要可扩展UV固化宽度的工业印刷"], "vi": ["In phun UV (ứng dụng chính)", "Đóng rắn sơn phủ trên máy in và máy phủ", "In lụa PCB và mực phủ hàn", "Môi trường hạn chế không gian cần đóng rắn UV cường độ cao", "In công nghiệp cần chiều rộng đóng rắn UV mở rộng được"]}, intro: {"en": "An air-cooled, scalable UV LED system with TargetCure and WhisperCure technology, digital/analog control, and optional Ethernet communication for high irradiance curing applications.", "zh": "风冷式、可扩展的UV LED系统，搭载TargetCure与WhisperCure技术，支持数字/模拟控制及可选以太网通信，适用于高辐照度固化应用。", "vi": "Hệ thống UV LED làm mát bằng khí, có thể mở rộng với công nghệ TargetCure và WhisperCure, điều khiển số/tương tự, và giao tiếp Ethernet tùy chọn cho ứng dụng đóng rắn độ rọi cao."}, features: {"en": ["TargetCure and WhisperCure technology", "Digital/analog control with optional Ethernet communication"], "zh": ["搭载TargetCure与WhisperCure技术", "支持数字/模拟控制及可选以太网通信"], "vi": ["Công nghệ TargetCure và WhisperCure", "Điều khiển số/tương tự với giao tiếp Ethernet tùy chọn"]} },
  "fj240": { applications: {"en": ["Digital inkjet printing requiring high UV dose and dwell time", "Wood coatings and surface finishing", "Scanning cure applications where maximum dose is critical", "Area cure applications demanding the highest curing performance", "Printing and coating where FJ100 or FireJet ONE output is insufficient"], "zh": ["需要高UV剂量与长驻留时间的数码喷墨印刷", "木材涂装与表面处理", "对最大剂量要求严苛的扫描固化应用", "要求最高固化性能的面固化应用", "FJ100或FireJet ONE输出不足时的印刷与涂装"], "vi": ["In phun kỹ thuật số cần liều UV cao và thời gian lưu dài", "Sơn phủ gỗ và hoàn thiện bề mặt", "Ứng dụng đóng rắn quét nơi liều tối đa là then chốt", "Ứng dụng đóng rắn diện tích đòi hỏi hiệu suất cao nhất", "In và phủ khi đầu ra FJ100 hoặc FireJet ONE không đủ"]}, intro: {"en": "An air-cooled, scalable UV LED system featuring TargetCure technology and high dose output, with digital/analog control and optional Ethernet communication.", "zh": "风冷式、可扩展的UV LED系统，搭载TargetCure技术，提供高剂量输出，支持数字/模拟控制及可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng khí, có thể mở rộng với công nghệ TargetCure và đầu ra liều cao, điều khiển số/tương tự và giao tiếp Ethernet tùy chọn."}, features: {"en": ["High dose output with TargetCure technology", "Scalable design with digital/analog control"], "zh": ["搭载TargetCure技术，提供高剂量输出", "可扩展设计，支持数字/模拟控制"], "vi": ["Đầu ra liều cao với công nghệ TargetCure", "Thiết kế mở rộng với điều khiển số/tương tự"]} },
  "fj801": { applications: {"en": ["Micro-speaker manufacturing", "Camera module (CCM) assembly", "Electronics manufacturing requiring large-area UV curing", "Medical device assembly", "Production lines upgrading from FJ800"], "zh": ["微型扬声器制造", "摄像头模组（CCM）组装", "需要大面积UV固化的电子制造", "医疗器械组装", "从FJ800升级的生产线"], "vi": ["Sản xuất loa siêu nhỏ", "Lắp ráp mô-đun camera (CCM)", "Sản xuất điện tử cần đóng rắn UV diện tích lớn", "Lắp ráp thiết bị y tế", "Dây chuyền nâng cấp từ FJ800"]}, intro: {"en": "An air-cooled UV LED area curing system featuring TargetCure technology, exceptional uniformity, and a separate controller, designed for area curing applications.", "zh": "风冷式UV LED面固化系统，搭载TargetCure技术，均匀性卓越，配备独立控制器，专为面固化应用设计。", "vi": "Hệ thống đóng rắn diện tích UV LED làm mát bằng khí với công nghệ TargetCure, độ đồng đều vượt trội, và bộ điều khiển riêng, được thiết kế cho ứng dụng đóng rắn diện tích."}, features: {"en": ["Exceptional uniformity for area curing applications", "Separate controller, scalable design"], "zh": ["面固化应用中均匀性卓越", "配备独立控制器，可扩展设计"], "vi": ["Độ đồng đều vượt trội cho ứng dụng đóng rắn diện tích", "Bộ điều khiển riêng, thiết kế mở rộng"]} },
  "fl200": { applications: {"en": ["Medical device UV curing assembly", "Web and conveyor-based UV curing systems", "Large-area UV LED curing on production lines", "Applications requiring scalable UV curing up to 2 m width"], "zh": ["医疗器械UV固化组装", "卷筒与传送带式UV固化系统", "生产线上的大面积UV LED固化", "需要固化宽度可扩展至2米的应用"], "vi": ["Lắp ráp đóng rắn UV thiết bị y tế", "Hệ thống đóng rắn UV dạng cuộn và băng tải", "Đóng rắn UV LED diện tích lớn trên dây chuyền sản xuất", "Ứng dụng cần đóng rắn UV mở rộng đến chiều rộng 2 m"]}, intro: {"en": "A water-cooled, scalable, small form factor UV LED system with a separate controller and Ethernet control, designed for compact installation requirements.", "zh": "水冷式、可扩展、体积小巧的UV LED系统，配备独立控制器，支持以太网控制，专为紧凑安装需求设计。", "vi": "Hệ thống UV LED làm mát bằng nước, có thể mở rộng, kích thước nhỏ gọn với bộ điều khiển riêng và điều khiển Ethernet, được thiết kế cho yêu cầu lắp đặt nhỏ gọn."}, features: {"en": ["Small form factor with separate controller", "Ethernet control for system integration"], "zh": ["体积小巧，配备独立控制器", "支持以太网控制，便于系统集成"], "vi": ["Kích thước nhỏ gọn với bộ điều khiển riêng", "Điều khiển Ethernet để tích hợp hệ thống"]} },
  "fl400": { applications: {"en": ["Digital inkjet printing", "Container screen printing", "Wood panel coating", "Web and conveyor-based UV curing", "Industrial large-area printing production lines"], "zh": ["数码喷墨印刷", "容器丝网印刷", "木板涂装", "卷筒与传送带式UV固化", "工业大幅面印刷生产线"], "vi": ["In phun kỹ thuật số", "In lưới trên chai lọ, bao bì", "Sơn phủ ván gỗ", "Đóng rắn UV dạng cuộn và băng tải", "Dây chuyền in công nghiệp khổ lớn"]}, intro: {"en": "A water-cooled, scalable UV LED system with digital/analog control, designed for high performance curing applications with optional Ethernet communication.", "zh": "水冷式、可扩展的UV LED系统，支持数字/模拟控制，专为高性能固化应用设计，并支持可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng nước, có thể mở rộng với điều khiển số/tương tự, được thiết kế cho ứng dụng đóng rắn hiệu suất cao với giao tiếp Ethernet tùy chọn."}, features: {"en": ["Scalable design with digital/analog control", "Suited for high performance curing applications"], "zh": ["可扩展设计，支持数字/模拟控制", "适用于高性能固化应用"], "vi": ["Thiết kế mở rộng với điều khiển số/tương tự", "Phù hợp cho ứng dụng đóng rắn hiệu suất cao"]} },
  "fl440": { applications: {"en": ["Demanding printing applications requiring maximum UV power", "Single-pass UV curing on high-speed production lines", "Industrial printing with wide-format exposure requirements", "Digital and commercial printing requiring maximum throughput"], "zh": ["要求最大UV功率的高要求印刷应用", "高速生产线上的单道次UV固化", "有宽幅曝光需求的工业印刷", "追求最大产能的数码与商业印刷"], "vi": ["Ứng dụng in khắt khe cần công suất UV tối đa", "Đóng rắn UV một lượt trên dây chuyền tốc độ cao", "In công nghiệp có yêu cầu phơi sáng khổ rộng", "In kỹ thuật số và thương mại cần năng suất tối đa"]}, intro: {"en": "A water-cooled, scalable UV LED system delivering high dose and high irradiance with digital/analog control, suited for high performance curing applications with optional Ethernet communication.", "zh": "水冷式、可扩展的UV LED系统，提供高剂量与高辐照度，支持数字/模拟控制，适用于高性能固化应用，并支持可选以太网通信。", "vi": "Hệ thống UV LED làm mát bằng nước, có thể mở rộng, mang lại liều cao và độ rọi cao với điều khiển số/tương tự, phù hợp cho ứng dụng đóng rắn hiệu suất cao với giao tiếp Ethernet tùy chọn."}, features: {"en": ["High dose and high irradiance output", "Suited for high performance curing applications"], "zh": ["提供高剂量与高辐照度输出", "适用于高性能固化应用"], "vi": ["Đầu ra liều cao và độ rọi cao", "Phù hợp cho ứng dụng đóng rắn hiệu suất cao"]} },
  "lighthammer-10": { applications: {"en": ["Converting, printing, and high-speed coating production lines", "Electronics, automotive, and fiber optics UV curing", "Medical device UV adhesive curing", "Industry 4.0 / smart manufacturing requiring IoT monitoring"], "zh": ["加工转换、印刷与高速涂装生产线", "电子、汽车与光纤UV固化", "医疗器械UV胶水固化", "需要物联网监控的工业4.0/智能制造"], "vi": ["Dây chuyền gia công chuyển đổi, in và phủ tốc độ cao", "Đóng rắn UV cho điện tử, ô tô và sợi quang", "Đóng rắn keo UV thiết bị y tế", "Sản xuất thông minh / Industry 4.0 cần giám sát IoT"]}, intro: {"en": "The ultra high output 10-inch lamp system and flagship of the Fusion UV range, delivering the full 240 W/cm power class with electronic shutter, variable power control, and optional industrial fieldbus protocols. Represents the latest generation of LightHammer technology with CE compliance.", "zh": "超高输出10英寸灯具系统，是Fusion UV产品线的旗舰型号，提供全功率等级240 瓦/厘米，配备电子快门、可变功率控制及可选工业现场总线协议。代表LightHammer技术的最新一代，符合CE认证标准。", "vi": "Hệ thống đèn 10 inch đầu ra siêu cao và là sản phẩm chủ lực của dòng Fusion UV, cung cấp cấp công suất đầy đủ 240 W/cm với cửa chớp điện tử, điều khiển công suất biến thiên, và giao thức fieldbus công nghiệp tùy chọn. Đại diện cho thế hệ công nghệ LightHammer mới nhất, đạt chứng nhận CE."}, features: {"en": ["Ultra high output flagship of the Fusion UV product range", "Electronic shutter and variable power (35-100%)", "Optional industrial fieldbus protocol support"], "zh": ["Fusion UV产品线超高输出旗舰型号", "电子快门与可变功率（35-100%）", "可选支持工业现场总线协议"], "vi": ["Sản phẩm chủ lực đầu ra siêu cao của dòng Fusion UV", "Cửa chớp điện tử và công suất biến thiên (35-100%)", "Hỗ trợ giao thức fieldbus công nghiệp tùy chọn"]} },
  "lighthammer-6": { applications: {"en": ["High-speed converting, printing, and coating production lines", "Electronics and automotive UV adhesive curing", "Fiber optics and medical device UV curing", "Industrial lines requiring modular, scalable UV curing width"], "zh": ["高速加工转换、印刷与涂装生产线", "电子与汽车UV胶水固化", "光纤与医疗器械UV固化", "需要模块化、可扩展UV固化宽度的工业产线"], "vi": ["Dây chuyền gia công chuyển đổi, in và phủ tốc độ cao", "Đóng rắn keo UV cho điện tử và ô tô", "Đóng rắn UV cho sợi quang và thiết bị y tế", "Dây chuyền công nghiệp cần chiều rộng đóng rắn UV mô-đun, mở rộng được"]}, intro: {"en": "A 6-inch electrodeless UV lamp system with variable power (35-100%) and quick restart, electronic shutter, and standard primary/secondary external control with optional industrial fieldbus protocols (DeviceNet, Profinet, Profibus, EtherNet/IP).", "zh": "采用6英寸灯泡的无极UV灯系统，支持可变功率（35-100%）及快速重启、电子快门，以及标配主/从外部控制，并可选配工业现场总线协议（DeviceNet、Profinet、Profibus、EtherNet/IP）。", "vi": "Hệ thống đèn UV không điện cực 6 inch với công suất biến thiên (35-100%) và khởi động lại nhanh, cửa chớp điện tử, và điều khiển ngoài chính/phụ tiêu chuẩn với giao thức fieldbus công nghiệp tùy chọn (DeviceNet, Profinet, Profibus, EtherNet/IP)."}, features: {"en": ["Variable power (35-100%) with quick restart capability", "Electronic shutter standard, optional mechanical", "Optional industrial fieldbus protocol support"], "zh": ["支持可变功率（35-100%），可快速重启", "标配电子快门，可选机械快门", "可选支持工业现场总线协议"], "vi": ["Công suất biến thiên (35-100%) với khả năng khởi động lại nhanh", "Cửa chớp điện tử tiêu chuẩn, tùy chọn cơ học", "Hỗ trợ giao thức fieldbus công nghiệp tùy chọn"]} },
  "ls200": { applications: {"en": ["UV LED spot curing process control and calibration in electronics assembly", "Medical device manufacturing quality assurance and compliance", "Automotive UV adhesive curing process verification", "Defense and aerospace manufacturing UV process monitoring", "R&D and laboratory UV LED characterization"], "zh": ["电子组装中UV LED点固化的过程控制与校准", "医疗器械制造的质量保证与合规", "汽车UV胶水固化工艺验证", "国防与航空航天制造中的UV工艺监控", "科研与实验室UV LED特性测量"], "vi": ["Kiểm soát và hiệu chuẩn quy trình đóng rắn UV LED điểm trong lắp ráp điện tử", "Đảm bảo chất lượng và tuân thủ trong sản xuất thiết bị y tế", "Kiểm chứng quy trình đóng rắn keo UV ô tô", "Giám sát quy trình UV trong sản xuất quốc phòng và hàng không vũ trụ", "Đo đặc tính UV LED trong R&D và phòng thí nghiệm"]}, intro: {"en": "Radiometry is essential for measuring light output from a UV curing system to maintain a precise, repeatable process. UV measuring systems must capture the narrow beam at the center of a detecting sensor at an exact focal height to determine peak irradiance. Two options are available: Irradiance (W/cm2) using the LS200 or Optical Power (W) using the LS200P, achieving unmatched control when used with a Beam Positioning Kit and LX500 controller.", "zh": "辐射测量是维持精准、可重复UV固化工艺的关键，用于测量UV固化系统的光输出。UV测量系统必须在精确焦距高度内、于检测传感器中心捕获窄光束，才能确定峰值辐照度。提供两种测量方案：使用LS200测量辐照度（W/cm²），或使用LS200P测量光功率（W）；搭配光束定位套件与LX500控制器使用时，可实现无可比拟的控制精度。", "vi": "Đo bức xạ là kỹ thuật thiết yếu để đo đầu ra ánh sáng từ hệ thống đóng rắn UV nhằm duy trì quy trình chính xác, có thể lặp lại. Hệ thống đo UV phải bắt được chùm tia hẹp tại tâm cảm biến ở đúng độ cao tiêu cự để xác định độ rọi đỉnh. Có hai tùy chọn: đo độ rọi (W/cm²) bằng LS200 hoặc công suất quang (W) bằng LS200P, đạt khả năng kiểm soát vượt trội khi dùng cùng Bộ định vị chùm tia và bộ điều khiển LX500."}, features: {"en": ["Accurate measurement with +/-10% accuracy and high resolution", "Optimized for monochromatic UV LED sources", "Compact design suitable for confined-area measurements"], "zh": ["测量精准，误差±10%，分辨率高", "针对单色UV LED光源优化", "紧凑设计，适合狭小空间测量"], "vi": ["Đo chính xác với độ chính xác +/-10% và độ phân giải cao", "Tối ưu cho nguồn UV LED đơn sắc", "Thiết kế nhỏ gọn phù hợp đo trong không gian hẹp"]} },
  "lx500": { applications: {"en": ["Medical device manufacturing (catheters, cannulas, endoscopes, syringes)", "Electronics assembly (CCM, smartphones, tablets, micro-speakers, lenses)", "Optoelectronics assembly", "Automotive and aerospace component bonding", "Pharmaceutical, semiconductor and general-purpose UV adhesive curing", "EV battery manufacturing reliability improvement"], "zh": ["医疗器械制造（导管、套管、内窥镜、注射器）", "电子组装（摄像头模组、智能手机、平板电脑、微型扬声器、镜头）", "光电组装", "汽车与航空航天部件粘接", "制药、半导体及通用UV胶水固化", "提升动力电池制造可靠性"], "vi": ["Sản xuất thiết bị y tế (ống thông, cannula, nội soi, ống tiêm)", "Lắp ráp điện tử (mô-đun camera, điện thoại thông minh, máy tính bảng, loa siêu nhỏ, ống kính)", "Lắp ráp quang điện tử", "Liên kết linh kiện ô tô và hàng không vũ trụ", "Đóng rắn keo UV trong dược phẩm, bán dẫn và đa dụng", "Nâng cao độ tin cậy trong sản xuất pin xe điện"]}, intro: {"en": "The LX500 V2 series delivers outstanding optical stability with proprietary Intelli-Lamp LED technology, exceptionally high peak irradiance, and unparalleled process control with StepCure 2.0. A newly designed 2.4-inch full color LCD provides flexible control via keypad, foot pedal, PLC, or USB, with real-time programming and data logging via Micro SD card.", "zh": "LX500 V2系列搭载专利Intelli-Lamp LED技术，光学稳定性出众，峰值辐照度极高，并通过StepCure 2.0实现无与伦比的工艺控制。全新设计的2.4英寸全彩液晶屏支持四向按键、脚踏开关、PLC或USB等多种控制方式，并可通过Micro SD卡实现实时编程与数据记录。", "vi": "Dòng LX500 V2 mang lại độ ổn định quang học vượt trội nhờ công nghệ Intelli-Lamp LED độc quyền, độ rọi đỉnh cực cao, và khả năng kiểm soát quy trình vô song với StepCure 2.0. Màn hình LCD màu 2.4 inch thiết kế mới cho phép điều khiển linh hoạt qua bàn phím, bàn đạp, PLC hoặc USB, cùng lập trình thời gian thực và ghi log dữ liệu qua thẻ Micro SD."}, features: {"en": ["Intelli-Lamp LED technology maintains optical stability +/-5% during exposure", "Integrated radiometer for quick calibration and accurate intensity measurement", "2.4-inch full color LCD with four-way keypad, foot pedal, PLC, or USB control"], "zh": ["Intelli-Lamp LED技术在曝光过程中保持±5%的光学稳定性", "集成辐射计，实现快速校准与精准强度测量", "2.4英寸全彩液晶屏，支持四向按键、脚踏、PLC或USB多种控制方式"], "vi": ["Công nghệ Intelli-Lamp LED duy trì độ ổn định quang học +/-5% trong khi phơi sáng", "Máy đo bức xạ tích hợp để hiệu chuẩn nhanh và đo cường độ chính xác", "Màn hình LCD màu 2.4 inch với điều khiển bàn phím 4 hướng, bàn đạp, PLC hoặc USB"]} },
  "nexus-ii": { applications: {"en": ["Flexographic printing (primary application)", "Industrial UV LED area curing on production lines", "High-temperature environment UV curing", "Production lines requiring maximum UV output consistency"], "zh": ["柔性版印刷（主要应用）", "生产线上的工业UV LED面固化", "高温环境UV固化", "要求UV输出一致性最高的生产线"], "vi": ["In flexo (ứng dụng chính)", "Đóng rắn diện tích UV LED công nghiệp trên dây chuyền sản xuất", "Đóng rắn UV trong môi trường nhiệt độ cao", "Dây chuyền yêu cầu độ nhất quán đầu ra UV tối đa"]}, intro: {"en": "A water-cooled high power UV LED system offering quiet operation and rugged reliability in tough environments, with Ethernet communications and easy mounting with a common form factor. Well suited to flexographic printing applications.", "zh": "水冷式高功率UV LED系统，运行安静，在恶劣环境下坚固可靠，支持以太网通信，采用通用结构便于安装。适用于柔印等印刷应用场景。", "vi": "Hệ thống UV LED công suất cao làm mát bằng nước, vận hành êm ái và bền bỉ trong môi trường khắc nghiệt, hỗ trợ giao tiếp Ethernet và dễ lắp đặt với kích thước tiêu chuẩn. Phù hợp cho ứng dụng in flexo."}, features: {"en": ["High power output with quiet operation", "Rugged and reliable in tough industrial environments"], "zh": ["高功率输出，运行安静", "在恶劣工业环境下坚固可靠"], "vi": ["Công suất đầu ra cao với vận hành êm ái", "Bền bỉ và đáng tin cậy trong môi trường công nghiệp khắc nghiệt"]} },
  "nexus-ii-ac": { applications: {"en": ["Flexographic printing (primary application)", "Industrial UV LED area curing on production lines", "Lines requiring chiller-free, low-maintenance integration"], "zh": ["柔性版印刷（主要应用）", "生产线上的工业UV LED面固化", "需要免冷水机、低维护集成的产线"], "vi": ["In flexo (ứng dụng chính)", "Đóng rắn diện tích UV LED công nghiệp trên dây chuyền sản xuất", "Dây chuyền cần tích hợp không máy làm lạnh, ít bảo trì"]}, intro: {"en": "An air-cooled UV LED system with reduced routine maintenance and no chiller needed, offering Ethernet communications and easy mounting with a common form factor. Well suited to flexographic printing applications.", "zh": "风冷式UV LED系统，日常维护需求更低，无需配置冷水机，支持以太网通信，采用通用结构便于安装。适用于柔印等印刷应用场景。", "vi": "Hệ thống UV LED làm mát bằng khí giảm bảo trì định kỳ và không cần máy làm lạnh, hỗ trợ giao tiếp Ethernet và dễ lắp đặt với kích thước tiêu chuẩn. Phù hợp cho ứng dụng in flexo."}, features: {"en": ["No chiller needed, reduced routine maintenance", "Ethernet communications, easy mounting with common form factor"], "zh": ["无需冷水机，日常维护需求降低", "支持以太网通信，通用结构便于安装"], "vi": ["Không cần máy làm lạnh, giảm bảo trì định kỳ", "Giao tiếp Ethernet, dễ lắp đặt với kích thước tiêu chuẩn"]} },
  "r2000": { applications: {"en": ["UV irradiance and power measurement for S2000 Elite, S2000 XLA and S1500 spot curing systems", "Process control and calibration in medical device manufacturing (catheters, cannulas, syringes, endoscopes)", "Electronics and optoelectronics UV curing process verification", "Multi-station manufacturing requiring consistent irradiance across all stations", "Automated and semi-automated UV curing lines requiring real-time monitoring", "Laboratory and R&D UV light output measurement"], "zh": ["S2000 Elite、S2000 XLA与S1500点固化系统的UV辐照度与功率测量", "医疗器械制造中的过程控制与校准（导管、套管、注射器、内窥镜）", "电子与光电UV固化工艺验证", "要求所有工位辐照度一致的多工位制造", "需要实时监控的自动化与半自动UV固化产线", "实验室与科研UV光输出测量"], "vi": ["Đo độ rọi và công suất UV cho hệ thống đóng rắn điểm S2000 Elite, S2000 XLA và S1500", "Kiểm soát quy trình và hiệu chuẩn trong sản xuất thiết bị y tế (ống thông, cannula, ống tiêm, nội soi)", "Kiểm chứng quy trình đóng rắn UV điện tử và quang điện tử", "Sản xuất nhiều trạm yêu cầu độ rọi đồng nhất trên mọi trạm", "Dây chuyền đóng rắn UV tự động và bán tự động cần giám sát thời gian thực", "Đo đầu ra ánh sáng UV trong phòng thí nghiệm và R&D"]}, intro: {"en": "Radiometry is essential for measuring UV light output to maintain a repeatable curing process. The R2000 Radiometer combines with the S2000 Elite/S2000 UV Spot Curing System to provide a complete curing station with unmatched control and repeatability. Special electronics allow connection of custom sensors that measure light energy directly at the cure site or within cure ring bonding fixtures.", "zh": "辐射测量是维持可重复UV固化工艺的关键技术，用于测量UV光输出。R2000辐射计可与S2000 Elite/S2000 UV点固化系统配合使用，组成具备无可比拟控制力与重复精度的完整固化工作站。其特殊电路设计支持连接定制传感器，可直接在固化点或固化环夹具内测量光能。", "vi": "Đo bức xạ là kỹ thuật thiết yếu để đo đầu ra ánh sáng UV nhằm duy trì quy trình đóng rắn có thể lặp lại. Máy đo bức xạ R2000 có thể kết hợp với Hệ thống đóng rắn điểm UV S2000 Elite/S2000 để tạo thành trạm đóng rắn hoàn chỉnh với khả năng kiểm soát và độ lặp lại vượt trội. Mạch điện tử đặc biệt cho phép kết nối cảm biến tùy chỉnh để đo năng lượng ánh sáng trực tiếp tại điểm đóng rắn hoặc trong đồ gá vòng đóng rắn."}, features: {"en": ["Combines with S2000 Elite/S2000 for complete curing station control", "Supports custom sensors for cure site and cure ring measurement"], "zh": ["可与S2000 Elite/S2000配合，组成完整固化工作站控制方案", "支持连接定制传感器，用于固化点和固化环测量"], "vi": ["Kết hợp với S2000 Elite/S2000 để kiểm soát trạm đóng rắn hoàn chỉnh", "Hỗ trợ cảm biến tùy chỉnh để đo tại điểm đóng rắn và vòng đóng rắn"]} },
  "s1500-pro": { applications: {"en": ["High-throughput UV adhesive curing in micro-electronic manufacturing", "Automated bonding processes in opto-electronic manufacturing", "Medical device manufacturing requiring precision, traceability, and automation", "Cleanroom manufacturing environments", "General industrial automated manufacturing with UV spot curing requirements"], "zh": ["微电子制造中的高产能UV胶水固化", "光电制造中的自动化粘接工艺", "要求精密、可追溯与自动化的医疗器械制造", "洁净室制造环境", "有UV点固化需求的通用工业自动化制造"], "vi": ["Đóng rắn keo UV năng suất cao trong sản xuất vi điện tử", "Quy trình liên kết tự động trong sản xuất quang điện tử", "Sản xuất thiết bị y tế yêu cầu chính xác, truy xuất nguồn gốc và tự động hóa", "Môi trường sản xuất phòng sạch", "Sản xuất công nghiệp tự động hóa đa dụng có nhu cầu đóng rắn UV điểm"]}, intro: {"en": "The latest addition to the OmniCure S-series lamp-based spot curing solutions, ideal for high-throughput UV adhesive curing and automated bonding processes in micro-electronic and opto-electronic manufacturing. Features Intelli-Lamp 2.0 technology, user-interchangeable optical filters, integrated StepCure 2.0, USB and SD card connectivity, and an intuitive LCD touch screen.", "zh": "OmniCure S系列灯式点固化解决方案的最新成员，适用于微电子和光电制造中高产能的UV胶水固化与自动化粘接工艺。配备Intelli-Lamp 2.0技术、用户可更换光学滤镜、集成StepCure 2.0、USB与SD卡连接，以及直观的液晶触摸屏界面。", "vi": "Sản phẩm mới nhất trong dòng giải pháp đóng rắn điểm sử dụng đèn của OmniCure S-series, lý tưởng cho quy trình đóng rắn keo UV và liên kết tự động hóa năng suất cao trong sản xuất vi điện tử và quang điện tử. Trang bị công nghệ Intelli-Lamp 2.0, bộ lọc quang có thể thay thế, StepCure 2.0 tích hợp, kết nối USB và thẻ SD, cùng màn hình cảm ứng LCD trực quan."}, features: {"en": ["Intelli-Lamp 2.0 technology enhances lamp life while maintaining performance", "User-interchangeable and customizable optical filters", "Industry 4.0 ready with programmable PLC output, Flight Recorder log, and NFC key card"], "zh": ["Intelli-Lamp 2.0技术延长灯泡寿命同时保持性能", "用户可更换、可定制的光学滤镜", "支持工业4.0，配备可编程PLC输出、飞行记录器日志和NFC密钥卡"], "vi": ["Công nghệ Intelli-Lamp 2.0 kéo dài tuổi thọ đèn trong khi duy trì hiệu suất", "Bộ lọc quang có thể thay thế và tùy chỉnh bởi người dùng", "Sẵn sàng Industry 4.0 với đầu ra PLC lập trình được, nhật ký Flight Recorder và thẻ khóa NFC"]} },
  "s2000-elite": { applications: {"en": ["Medical device assembly: catheters, cannulas, blood oxygenators, syringes, endoscopes", "Electronics and optoelectronics precision adhesive curing", "Automated and semi-automated high-throughput manufacturing lines", "Academic, development and laboratory UV curing applications", "Industry 4.0 smart manufacturing requiring remote monitoring"], "zh": ["医疗器械组装：导管、套管、血液氧合器、注射器、内窥镜", "电子与光电精密胶水固化", "自动化与半自动高产能生产线", "学术、研发与实验室UV固化应用", "需要远程监控的工业4.0智能制造"], "vi": ["Lắp ráp thiết bị y tế: ống thông, cannula, máy oxy hóa máu, ống tiêm, nội soi", "Đóng rắn keo chính xác trong điện tử và quang điện tử", "Dây chuyền sản xuất năng suất cao tự động và bán tự động", "Ứng dụng đóng rắn UV trong học thuật, phát triển và phòng thí nghiệm", "Sản xuất thông minh Industry 4.0 cần giám sát từ xa"]}, intro: {"en": "A new generation lamp-based UV spot curing system designed for the most demanding manufacturing applications. Offers a powerful 200 Watt lamp with a guaranteed life of 2000 hours, proprietary Closed-Loop Feedback technology that monitors light output in real time and automatically corrects within +/-5%, a 4.3\" touch screen, and StepCure 2.0 with 7 programmable PLC output channels for Industry 4.0 integration.", "zh": "新一代灯式UV点固化系统，专为最严苛的制造应用而设计。配备200瓦大功率灯，保证寿命2000小时；搭载专利闭环反馈（Closed-Loop Feedback）技术，实时监测光输出并自动修正，误差控制在±5%以内；配有4.3英寸触摸屏，以及具备7个可编程PLC输出通道的StepCure 2.0系统，可轻松接入工业4.0环境。", "vi": "Hệ thống đóng rắn UV điểm thế hệ mới sử dụng đèn, được thiết kế cho các ứng dụng sản xuất khắt khe nhất. Trang bị đèn công suất 200W với tuổi thọ bảo hành 2000 giờ, công nghệ phản hồi vòng kín (Closed-Loop Feedback) độc quyền giám sát đầu ra ánh sáng theo thời gian thực và tự động hiệu chỉnh trong phạm vi ±5%, màn hình cảm ứng 4.3 inch, cùng StepCure 2.0 với 7 kênh đầu ra PLC lập trình được, sẵn sàng tích hợp Industry 4.0."}, features: {"en": ["Closed-Loop Feedback and Intelli-lamp technology guarantee precise dosage delivery", "Plug-and-play compatibility with existing S2000/S1500 production lines", "Calibration with OmniCure R2000 Radiometer, remote control via WEB UI", "StepCure 2.0 with PLC control enhances automation for Industry 4.0"], "zh": ["闭环反馈与Intelli-lamp技术确保精准剂量输出", "即插即用，兼容现有S2000/S1500生产线", "可配合OmniCure R2000辐射计校准，支持WEB UI远程控制管理", "StepCure 2.0配合PLC控制，提升自动化水平，适配工业4.0"], "vi": ["Công nghệ phản hồi vòng kín và Intelli-lamp đảm bảo cấp liều chính xác", "Tương thích cắm-và-chạy với dây chuyền sản xuất S2000/S1500 hiện có", "Hiệu chuẩn cùng máy đo bức xạ OmniCure R2000, điều khiển từ xa qua WEB UI", "StepCure 2.0 với điều khiển PLC tăng cường tự động hóa cho Industry 4.0"]} },
  "semray-5000": { applications: {"en": ["Wide web printing (flexographic and other wide-format web printing)", "Roll-to-roll printing", "Sheet-fed offset printing (UV curing between sheets for dry-sheet concept)", "Industrial large-format print applications requiring longer working distances", "Printing on heat-sensitive substrates"], "zh": ["宽幅卷筒印刷（柔印及其他宽幅卷筒印刷）", "卷对卷印刷", "单张胶印（张间UV固化，实现干张概念）", "需要较大工作距离的工业大幅面印刷应用", "热敏基材印刷"], "vi": ["In cuộn khổ rộng (flexo và các loại in cuộn khổ rộng khác)", "In cuộn-sang-cuộn", "In offset tờ rời (đóng rắn UV giữa các tờ theo khái niệm tờ khô)", "Ứng dụng in công nghiệp khổ lớn cần khoảng cách làm việc xa hơn", "In trên vật liệu nhạy nhiệt"]}, intro: {"en": "Designed for higher performance and flexible integration especially for larger working distances, the Semray UV5000+ Series is a water-cooled system. The emission window size is scalable in width from 400 to 1300mm in 50mm steps, with housing dimensions scalable accordingly.", "zh": "Semray UV5000+系列为水冷式系统，专为更高性能与灵活集成而设计，尤其适合较大工作距离的应用场景。发光窗口宽度可在400至1300毫米范围内以50毫米为步进进行调整，外壳尺寸相应可调。", "vi": "Được thiết kế cho hiệu suất cao hơn và tích hợp linh hoạt, đặc biệt phù hợp với khoảng cách làm việc lớn hơn, dòng Semray UV5000+ là hệ thống làm mát bằng nước. Kích thước cửa sổ phát quang có thể điều chỉnh theo chiều rộng từ 400 đến 1300mm theo bước 50mm, kích thước vỏ máy điều chỉnh tương ứng."}, features: {"en": ["Designed for larger working distances with flexible integration", "Emission window scalable from 400 to 1300mm in 50mm steps"], "zh": ["专为大工作距离与灵活集成而设计", "发光窗口宽度可在400至1300毫米之间以50毫米为步进调整"], "vi": ["Thiết kế cho khoảng cách làm việc lớn với tích hợp linh hoạt", "Cửa sổ phát quang điều chỉnh từ 400 đến 1300mm theo bước 50mm"]} },
  "semray-pc6003": { applications: {"en": ["Optical fiber draw tower coating cure", "Wire marking and wire coating cure", "360° cure of cylindrical substrates", "High-speed continuous fiber/wire production lines"], "zh": ["光纤拉丝塔涂层固化", "线材标识与线材涂层固化", "圆柱形基材的360°固化", "高速连续光纤/线材生产线"], "vi": ["Đóng rắn lớp phủ tháp kéo sợi quang", "Đóng rắn đánh dấu và phủ dây", "Đóng rắn 360° cho vật liệu hình trụ", "Dây chuyền sản xuất sợi/dây liên tục tốc độ cao"]}, intro: {"en": "A UV LED curing system designed from the ground up for optical fiber draw and wire marking manufacturing processes, providing 360° curing coverage.", "zh": "UV PC6003是一款从零开始专为光纤拉丝与线材标识制造工艺设计的UV LED固化系统，提供360°全方位固化覆盖。", "vi": "Hệ thống đóng rắn UV LED được thiết kế từ đầu cho quy trình sản xuất kéo sợi quang và đánh dấu dây, cung cấp phạm vi đóng rắn 360°."}, features: {"en": ["Purpose-built for optical fiber draw and wire marking processes", "360° curing coverage"], "zh": ["专为光纤拉丝与线材标识工艺打造", "360°全方位固化覆盖"], "vi": ["Được chế tạo riêng cho quy trình kéo sợi quang và đánh dấu dây", "Phạm vi đóng rắn 360°"]} },
  "semray-uv5052m": { applications: {"en": ["High-dose industrial UV LED curing", "Applications requiring high intensity at large working distances", "Wide-format coating and printing processes", "Custom-engineered production line integration"], "zh": ["高剂量工业UV LED固化", "需要大工作距离下高强度的应用", "宽幅涂装与印刷工艺", "定制化生产线集成"], "vi": ["Đóng rắn UV LED công nghiệp liều cao", "Ứng dụng cần cường độ cao ở khoảng cách làm việc lớn", "Quy trình sơn phủ và in khổ rộng", "Tích hợp dây chuyền sản xuất theo thiết kế riêng"]}, intro: {"en": "Equipped with special optics to bring more energy to the process, the Semray UV5052M is an example of customized UV LED development. A set of unique optical concepts direct photons from the UV-LED chips to larger working distances for greater flexibility in applications, minimum loss of energy and straylight, and focused UV intensity.", "zh": "UV5052M配备特殊光学系统，可为工艺过程提供更高能量，是Semray定制化UV LED开发的代表案例之一。独特的光学设计可将UV-LED芯片发出的光子引导至更大的工作距离，从而提升应用灵活性、最大限度降低能量损耗与杂散光，并实现聚焦的UV强度输出。", "vi": "Được trang bị quang học đặc biệt để mang lại nhiều năng lượng hơn cho quy trình, Semray UV5052M là ví dụ điển hình của phát triển UV LED tùy chỉnh. Một loạt khái niệm quang học độc đáo định hướng photon từ chip UV-LED đến khoảng cách làm việc lớn hơn, mang lại tính linh hoạt cao hơn trong ứng dụng, giảm thiểu thất thoát năng lượng và tán xạ, và cường độ UV tập trung."}, features: {"en": ["Dedicated optics for high intensity even at large working distances", "Customizable in sizes, lengths, connections, and optical concepts"], "zh": ["专用光学设计，即使在大工作距离下也能保持高强度", "尺寸、长度、接口及光学方案均可定制"], "vi": ["Quang học chuyên dụng cho cường độ cao ngay cả ở khoảng cách làm việc lớn", "Có thể tùy chỉnh về kích thước, chiều dài, kết nối và khái niệm quang học"]} },
  "vericure": { applications: {"en": ["Industrial wide-format coatings", "Web and conveyor-based printing applications", "Wood coating — floors, furniture, panels", "High-speed production lines requiring high dose at high line speeds", "Eco-conscious manufacturing (no mercury, no ozone)"], "zh": ["工业宽幅涂装", "卷筒与传送带式印刷应用", "木材涂装——地板、家具、板材", "需要高线速下高剂量的高速生产线", "环保制造（无汞、无臭氧）"], "vi": ["Sơn phủ công nghiệp khổ rộng", "Ứng dụng in dạng cuộn và băng tải", "Sơn phủ gỗ — sàn, nội thất, ván", "Dây chuyền tốc độ cao cần liều cao ở tốc độ dây chuyền lớn", "Sản xuất thân thiện môi trường (không thủy ngân, không ozone)"]}, intro: {"en": "A water-cooled UV LED system delivering ultra-high UV dose in a wide lamp format, up to 500 mJ/cm2 dose at 50mm working distance. Offers quiet operation and rugged reliability in tough environments, with Ethernet and analog communications. Well suited to high performance applications such as wood coatings.", "zh": "水冷式UV LED系统，以宽幅灯具形式提供超高UV剂量，工作距离50毫米时剂量最高可达500 mJ/cm²。运行安静，在恶劣环境下坚固可靠，支持以太网与模拟通信。适用于木材涂层等高性能应用场景。", "vi": "Hệ thống UV LED làm mát bằng nước cung cấp liều UV siêu cao ở định dạng đèn rộng, đạt tới 500 mJ/cm² ở khoảng cách làm việc 50mm. Vận hành êm ái và độ bền cao trong môi trường khắc nghiệt, hỗ trợ giao tiếp Ethernet và tương tự. Phù hợp cho ứng dụng hiệu suất cao như sơn phủ gỗ."}, features: {"en": ["Ultra-high UV dose up to 500 mJ/cm2 at 50mm working distance", "Quiet operation, rugged and reliable in tough environments", "Ethernet and analog communications, easy mounting with common form factor"], "zh": ["超高UV剂量，50毫米工作距离下最高可达500 mJ/cm²", "运行安静，在恶劣环境下坚固可靠", "支持以太网与模拟通信，采用通用结构便于安装"], "vi": ["Liều UV siêu cao lên đến 500 mJ/cm² ở khoảng cách làm việc 50mm", "Vận hành êm ái, bền bỉ và đáng tin cậy trong môi trường khắc nghiệt", "Giao tiếp Ethernet và tương tự, dễ lắp đặt với kích thước tiêu chuẩn"]} },
  "v3-led-heads": { intro: {"en": "Designed for use with the OmniCure LX500 Controller, the OmniCure V3 UV LED Heads feature next-generation high-output UV LEDs delivering best-in-class optical performance. With up to 120% increased optical power and up to 165% increase in peak irradiance compared to the predecessor MAX LED Heads, the V3 Heads deliver high dosage distributed uniformly across the spot area for faster, more consistent cures with greater control. Available in 365, 385, 395 and 405 nm wavelengths, delivering up to 22 W/cm² peak irradiance and 1,100 mW power with an exceptionally uniform beam profile.", "zh": "OmniCure V3 UV LED灯头专为搭配OmniCure LX500控制器使用而设计，采用新一代高输出UV LED，光学性能同类领先。与前代MAX LED灯头相比，光功率最高提升120%，峰值辐照度最高提升165%；V3灯头在整个光斑区域内均匀输出高剂量UV能量，固化更快、更一致、更易控制。提供365、385、395与405 nm波长，峰值辐照度最高22 W/cm²，光功率最高1,100 mW，光束分布异常均匀。", "vi": "Được thiết kế để sử dụng cùng bộ điều khiển OmniCure LX500, đầu UV LED OmniCure V3 sử dụng LED UV công suất cao thế hệ mới mang lại hiệu suất quang học hàng đầu. Với công suất quang tăng đến 120% và độ rọi đỉnh tăng đến 165% so với đầu MAX LED tiền nhiệm, đầu V3 cung cấp liều cao phân bố đồng đều trên toàn vùng chiếu, giúp đóng rắn nhanh hơn, nhất quán hơn với khả năng kiểm soát tốt hơn. Có các bước sóng 365, 385, 395 và 405 nm, độ rọi đỉnh lên đến 22 W/cm² và công suất 1.100 mW với chùm tia đồng đều vượt trội."}, features: {"en": ["Class-leading irradiance and optical power at 365, 385, 395 and 405 nm", "Up to 22 W/cm² peak irradiance and 1,100 mW total optical power", "Improved radiation distribution across the beam cross-section for consistent, controlled curing", "Up to 120% increased optical power vs. predecessor MAX LED Heads", "More energy efficient, lower maintenance, and longer service life", "Wide range of cross-compatible accessories: focusing lenses, adapters, extension cables", "Backward compatible with existing LX500 Controller", "Paired with LX500 for outstanding ±5% optical stability"], "zh": ["365、385、395与405 nm波长下同类领先的辐照度与光功率", "峰值辐照度最高22 W/cm²，总光功率最高1,100 mW", "光束截面辐射分布更优，固化一致、可控", "相较前代MAX LED灯头，光功率最高提升120%", "更节能、维护更少、使用寿命更长", "丰富的交叉兼容配件：聚焦镜头、适配器、延长线缆", "向下兼容现有LX500控制器", "搭配LX500可实现出色的±5%光学稳定性"], "vi": ["Độ rọi và công suất quang hàng đầu ở các bước sóng 365, 385, 395 và 405 nm", "Độ rọi đỉnh đến 22 W/cm² và tổng công suất quang 1.100 mW", "Phân bố bức xạ cải thiện trên tiết diện chùm tia giúp đóng rắn nhất quán, có kiểm soát", "Công suất quang tăng đến 120% so với đầu MAX LED tiền nhiệm", "Tiết kiệm năng lượng hơn, ít bảo trì hơn và tuổi thọ dài hơn", "Nhiều phụ kiện tương thích chéo: thấu kính hội tụ, bộ chuyển đổi, cáp nối dài", "Tương thích ngược với bộ điều khiển LX500 hiện có", "Kết hợp cùng LX500 đạt độ ổn định quang học ±5% vượt trội"]}, applications: {"en": ["Precision UV adhesive curing in medical device assembly (catheters, endoscopes)", "Electronics: camera modules, smartphones, tablets, micro-speakers, lenses", "High-throughput industrial manufacturing requiring repeatable UV spot curing", "EV battery manufacturing adhesive bonding", "Optoelectronics assembly"], "zh": ["医疗器械组装中的精密UV胶水固化（导管、内窥镜）", "电子产品：摄像头模组、智能手机、平板电脑、微型扬声器、镜头", "需要可重复UV点固化的高产能工业制造", "动力电池制造中的胶粘接合", "光电组装"], "vi": ["Đóng rắn keo UV chính xác trong lắp ráp thiết bị y tế (ống thông, nội soi)", "Điện tử: mô-đun camera, điện thoại thông minh, máy tính bảng, loa siêu nhỏ, ống kính", "Sản xuất công nghiệp năng suất cao cần đóng rắn UV điểm lặp lại được", "Liên kết keo trong sản xuất pin xe điện", "Lắp ráp quang điện tử"]} },
  "s2e-network-module": { intro: {"en": "The OmniCure S2E Network Module is designed to save time on maintenance and keep production running smoothly with remote process monitoring and UV curing equipment control. The S2E complements the OmniCure family of S-Series spot UV curing systems, offering the same high level of innovation, quality and reliability that customers expect. The S2E Ethernet adapter enables production facilities to remotely access up to 300 UV curing systems within a local area network, while simultaneously monitoring their activity and maintenance requirements through the OmniCure Monitoring Station software.", "zh": "OmniCure S2E网络模块旨在通过远程过程监控与UV固化设备控制，节省维护时间并保障生产顺畅运行。S2E是OmniCure S系列点UV固化系统的配套产品，秉承客户所期待的高水准创新、品质与可靠性。S2E以太网适配器使生产设施可在局域网内远程访问多达300台UV固化系统，并通过OmniCure监控站（Monitoring Station）软件同时监控其运行状态与维护需求。", "vi": "Mô-đun mạng OmniCure S2E được thiết kế để tiết kiệm thời gian bảo trì và giữ cho sản xuất vận hành trơn tru nhờ giám sát quy trình từ xa và điều khiển thiết bị đóng rắn UV. S2E bổ trợ cho dòng hệ thống đóng rắn UV điểm S-Series của OmniCure, mang cùng mức độ đổi mới, chất lượng và độ tin cậy mà khách hàng mong đợi. Bộ chuyển đổi Ethernet S2E cho phép nhà máy truy cập từ xa tới 300 hệ thống đóng rắn UV trong mạng cục bộ, đồng thời giám sát hoạt động và nhu cầu bảo trì qua phần mềm OmniCure Monitoring Station."}, features: {"en": ["Save maintenance time and keep production running smoothly with OmniCure Monitoring Station software", "Proactively trend and predict maintenance requirements with continuous operational data logging", "Enhance visibility of production activity and quickly isolate issues that result in potential waste/rework", "Increase productivity and eliminate time lost identifying system faults with real-time email alerts", "Remotely access and monitor up to 300 UV curing systems on a local area network", "Adds StepCure® process functionality to the S1500"], "zh": ["借助OmniCure监控站软件节省维护时间，保障生产顺畅运行", "持续记录运行数据，主动分析趋势并预测维护需求", "提升生产活动可视性，快速定位可能导致浪费/返工的问题", "实时邮件报警，提高生产效率，免去排查系统故障的时间损失", "可在局域网内远程访问并监控多达300台UV固化系统", "为S1500增加StepCure®工艺功能"], "vi": ["Tiết kiệm thời gian bảo trì và giữ sản xuất trơn tru với phần mềm OmniCure Monitoring Station", "Ghi dữ liệu vận hành liên tục để chủ động phân tích xu hướng và dự đoán nhu cầu bảo trì", "Tăng khả năng quan sát hoạt động sản xuất, nhanh chóng khoanh vùng sự cố gây lãng phí/làm lại", "Cảnh báo email thời gian thực giúp tăng năng suất, loại bỏ thời gian truy tìm lỗi hệ thống", "Truy cập và giám sát từ xa tới 300 hệ thống đóng rắn UV trong mạng cục bộ", "Bổ sung chức năng quy trình StepCure® cho S1500"]}, applications: {"en": ["Remote process monitoring of OmniCure S2000 and S1500 spot curing systems", "Multi-station production floors requiring centralized UV equipment oversight", "Predictive maintenance and operational data logging", "Production environments requiring real-time fault email alerts and electronic records"], "zh": ["OmniCure S2000与S1500点固化系统的远程过程监控", "需要集中管理UV设备的多工位生产车间", "预测性维护与运行数据记录", "需要实时故障邮件报警与电子记录的生产环境"], "vi": ["Giám sát quy trình từ xa cho hệ thống đóng rắn điểm OmniCure S2000 và S1500", "Xưởng sản xuất nhiều trạm cần quản lý tập trung thiết bị UV", "Bảo trì dự đoán và ghi dữ liệu vận hành", "Môi trường sản xuất cần cảnh báo lỗi qua email thời gian thực và hồ sơ điện tử"]} },
  "s-series-light-guides": { intro: {"en": "The OmniCure S Series offers a variety of light guides ranging from single and multi-legged to liquid-filled or fiber light guides, as well as a range of optical adapters to best meet customer requirements.", "zh": "OmniCure S系列提供多种导光管，涵盖单腿、多腿、液体填充与光纤导光管，并配有多种光学适配器，以最大程度满足客户需求。", "vi": "Dòng OmniCure S-Series cung cấp nhiều loại ống dẫn sáng, từ loại một nhánh, nhiều nhánh đến loại chứa chất lỏng hoặc sợi quang, cùng nhiều bộ chuyển đổi quang học để đáp ứng tốt nhất yêu cầu của khách hàng."}, features: {"en": ["Liquid Light Guide: 3, 5 and 8 mm tip diameters; standard lengths 750–3000 mm; dual and triple-leg configurations for multi-site curing", "High-Power Fiber Light Guide: equal distribution of light energy to multiple cure sites from a single light source", "High-Power Fiber Light Line: high-output linear beam; continuous fibers from input to termination eliminate coupling losses", "UV Cure-Ring Optical Adapter: 360° curing power; solid or slotted versions for Liquid Light Guides", "UV Light-Line Optical Adapter: focused linear beam for small rows of components, tubing and cables (up to 2\" line length)", "Adjustable Spot Collimating Adapter: uniform spot from 1\" up to 6\" (2.54–15.2 cm) for even power distribution"], "zh": ["液体导光管：端头直径3、5、8毫米；标准长度750–3000毫米；提供双腿与三腿配置，支持多点位固化", "大功率光纤导光管：将单一光源的光能均等分配到多个固化点位", "大功率光纤线光源：高输出线性光束；光纤从输入到末端连续贯通，消除耦合损耗", "UV固化环光学适配器：360°固化能力；提供实心与开槽两种版本，适配液体导光管", "UV线光光学适配器：聚焦线性光束，适用于小型元件排、管材与线缆（线长最长2英寸）", "可调光斑准直适配器：光斑1–6英寸（2.54–15.2厘米）均匀可调，功率分布均衡"], "vi": ["Ống dẫn sáng chất lỏng: đường kính đầu 3, 5 và 8 mm; chiều dài tiêu chuẩn 750–3000 mm; cấu hình hai và ba nhánh cho đóng rắn nhiều vị trí", "Ống dẫn sáng sợi quang công suất cao: phân bổ đều năng lượng ánh sáng từ một nguồn tới nhiều vị trí đóng rắn", "Đường sáng sợi quang công suất cao: chùm tia tuyến tính đầu ra cao; sợi quang liền mạch từ đầu vào đến đầu cuối loại bỏ tổn hao ghép nối", "Bộ chuyển đổi quang vòng đóng rắn UV: đóng rắn 360°; phiên bản đặc hoặc xẻ rãnh cho ống dẫn sáng chất lỏng", "Bộ chuyển đổi quang đường sáng UV: chùm tia tuyến tính hội tụ cho hàng linh kiện nhỏ, ống và cáp (chiều dài đường sáng đến 2\")", "Bộ chuẩn trực điểm điều chỉnh được: điểm sáng đồng đều từ 1\" đến 6\" (2,54–15,2 cm) cho phân bố công suất đều"]}, applications: {"en": ["Multi-site simultaneous curing with multi-leg light guides", "360° radial curing of catheters and tubing via Cure-Ring adapter", "Linear curing of component rows, tubing and cables via Light-Line adapter", "Uniform large-spot curing via the adjustable collimating adapter"], "zh": ["多腿导光管实现多点位同步固化", "通过固化环适配器对导管与管材进行360°径向固化", "通过线光适配器对元件排、管材与线缆进行线性固化", "通过可调准直适配器实现均匀大光斑固化"], "vi": ["Đóng rắn đồng thời nhiều vị trí với ống dẫn sáng nhiều nhánh", "Đóng rắn hướng tâm 360° cho ống thông và ống dẫn bằng bộ chuyển đổi vòng đóng rắn", "Đóng rắn tuyến tính hàng linh kiện, ống và cáp bằng bộ chuyển đổi đường sáng", "Đóng rắn điểm lớn đồng đều bằng bộ chuẩn trực điều chỉnh được"]} },
  "fl400-i": { intro: {"en": "The FireLine FL400-i Industrial UV LED Area Curing System is specifically designed for demanding industrial coating and adhesive curing in harsh, high-contaminant environments such as pipe coating and metal finishing. It features a newly engineered IP66-rated enclosure with robust endcaps, advanced window sealing, and optional sacrificial glass to shield primary optics from heat, dust and impact — delivering the same industry-leading optical uniformity and high dose performance as the original FL400.", "zh": "FireLine FL400-i工业UV LED面固化系统专为管道涂层、金属表面处理等高污染、严苛工业环境中的涂层与胶水固化而设计。全新工程化设计的IP66防护外壳配备坚固端盖与先进窗口密封，并可选牺牲玻璃保护主光学元件免受高温、粉尘与冲击——同时提供与原版FL400相同的行业领先光学均匀性与高剂量性能。", "vi": "Hệ thống đóng rắn diện tích UV LED công nghiệp FireLine FL400-i được thiết kế riêng cho đóng rắn sơn phủ và keo dán công nghiệp khắt khe trong môi trường khắc nghiệt, nhiều bụi bẩn như phủ ống và hoàn thiện kim loại. Vỏ máy đạt chuẩn IP66 thiết kế mới với nắp hai đầu chắc chắn, đệm kín cửa sổ tiên tiến, và kính hy sinh tùy chọn bảo vệ quang học chính khỏi nhiệt, bụi và va đập — mang lại độ đồng đều quang học hàng đầu và hiệu suất liều cao như FL400 nguyên bản."}, features: {"en": ["IP66-rated ruggedized enclosure for harsh, high-contaminant environments", "Advanced window sealing protects against heat, liquid, and dirt intrusion", "Versatile connection options: straight or barbed water fittings", "CDA (clean, dry air) ports to protect against condensation", "Optional sacrificial glass to shield primary optics", "Same optical uniformity and high dose performance as FL400", "Robust endcaps engineered for challenging industrial environments"], "zh": ["IP66防护等级的坚固外壳，适应高污染严苛环境", "先进窗口密封，防止高温、液体与灰尘侵入", "灵活的连接选项：直通或倒刺式水路接头", "CDA（洁净干燥空气）接口，防止冷凝", "可选牺牲玻璃，保护主光学元件", "与FL400相同的光学均匀性与高剂量性能", "坚固端盖，专为严苛工业环境打造"], "vi": ["Vỏ máy gia cố đạt IP66 cho môi trường khắc nghiệt, nhiều bụi bẩn", "Đệm kín cửa sổ tiên tiến chống nhiệt, chất lỏng và bụi bẩn xâm nhập", "Tùy chọn kết nối linh hoạt: đầu nối nước thẳng hoặc có ngạnh", "Cổng CDA (khí sạch, khô) chống ngưng tụ", "Kính hy sinh tùy chọn bảo vệ quang học chính", "Độ đồng đều quang học và hiệu suất liều cao như FL400", "Nắp hai đầu chắc chắn được thiết kế cho môi trường công nghiệp khắc nghiệt"]}, applications: {"en": ["Pipe coating UV curing in industrial environments", "Metal finishing and surface coating curing", "Adhesive curing in high-contamination, high-temperature environments", "Applications requiring IP66-rated UV curing equipment"], "zh": ["工业环境中的管道涂层UV固化", "金属表面处理与涂层固化", "高污染、高温环境中的胶水固化", "需要IP66防护等级UV固化设备的应用"], "vi": ["Đóng rắn UV lớp phủ ống trong môi trường công nghiệp", "Đóng rắn hoàn thiện kim loại và sơn phủ bề mặt", "Đóng rắn keo trong môi trường nhiệt độ cao, nhiều bụi bẩn", "Ứng dụng yêu cầu thiết bị đóng rắn UV đạt IP66"]} },
  "fe400": { intro: {"en": "The FireEdge FE400 air-cooled UV LED curing system offers advanced features with maximum flexibility, including built-in intensity control for both full-cure and UV inkjet pinning applications. It features patented Semiconductor Light Matrix (SLM) technology for process stability and is available in lengths from 80 mm to 240 mm. Segment control allows half the light source to be disabled for precise UV coverage, and a Hub can manage up to six light sources.", "zh": "FireEdge FE400风冷式UV LED固化系统功能先进、灵活性极高，内置强度控制，同时适用于完全固化与UV喷墨点固化应用。采用专利半导体光矩阵（SLM）技术保障工艺稳定性，提供80毫米至240毫米多种长度。分段控制可关闭一半光源以实现精准UV覆盖，一个集线器（Hub）最多可管理六个光源。", "vi": "Hệ thống đóng rắn UV LED làm mát bằng khí FireEdge FE400 cung cấp các tính năng tiên tiến với độ linh hoạt tối đa, gồm điều khiển cường độ tích hợp cho cả ứng dụng đóng rắn hoàn toàn và định hình mực in phun UV. Sử dụng công nghệ ma trận ánh sáng bán dẫn (SLM) được cấp bằng sáng chế cho độ ổn định quy trình, có các chiều dài từ 80 mm đến 240 mm. Điều khiển phân đoạn cho phép tắt một nửa nguồn sáng để phủ UV chính xác, và một Hub có thể quản lý tới sáu nguồn sáng."}, features: {"en": ["Built-in intensity control: full-cure, low-intensity (pinning), and half-source modes", "Patented SLM technology for process stability and repeatable output", "Available lengths: 80, 120, 160, 180, 240 mm", "Air-cooled — no water connections required", "Segment control: disable left or right half for precise UV coverage", "Scalable: stack end-to-end for contiguous uniform UV output", "Hub supports up to six light sources, managed as a single unit"], "zh": ["内置强度控制：完全固化、低强度（点固化）与半光源模式", "专利SLM技术，保障工艺稳定与输出可重复", "可选长度：80、120、160、180、240毫米", "风冷设计，无需水路连接", "分段控制：可关闭左半或右半光源，实现精准UV覆盖", "可扩展：首尾拼接实现连续均匀的UV输出", "集线器最多支持六个光源，可作为单一整体管理"], "vi": ["Điều khiển cường độ tích hợp: chế độ đóng rắn hoàn toàn, cường độ thấp (định hình) và nửa nguồn", "Công nghệ SLM được cấp bằng sáng chế cho quy trình ổn định và đầu ra lặp lại được", "Chiều dài có sẵn: 80, 120, 160, 180, 240 mm", "Làm mát bằng khí — không cần kết nối nước", "Điều khiển phân đoạn: tắt nửa trái hoặc phải để phủ UV chính xác", "Mở rộng được: ghép nối tiếp cho đầu ra UV liền mạch, đồng đều", "Hub hỗ trợ tới sáu nguồn sáng, quản lý như một khối duy nhất"]}, applications: {"en": ["Digital inkjet printing (UV pinning and full cure)", "UV adhesive curing in electronics and optics assembly", "3D printing UV curing", "Coating curing in web and sheet-fed printing"], "zh": ["数码喷墨印刷（UV点固化与完全固化）", "电子与光学组装中的UV胶水固化", "3D打印UV固化", "卷筒与单张印刷中的涂层固化"], "vi": ["In phun kỹ thuật số (định hình UV và đóng rắn hoàn toàn)", "Đóng rắn keo UV trong lắp ráp điện tử và quang học", "Đóng rắn UV trong in 3D", "Đóng rắn sơn phủ trong in cuộn và in tờ rời"]} },
  "fj800": { intro: {"en": "The Phoseon FireJet FJ800 UV LED Curing System is a large-area curing solution for adhesive and coating applications requiring low irradiance and long dwell time on large-scale production lines. Starting with a 100 mm × 100 mm base curing area, the modular components scale in all four directions, providing contiguous, uniform UV illumination. Operated by a simple controller supporting up to six light sources, the FJ800 is available in 365 and 395 nm wavelengths.", "zh": "Phoseon FireJet FJ800 UV LED固化系统是一款大面积固化解决方案，适用于大规模生产线上需要低辐照度、长驻留时间的胶水与涂层应用。以100毫米×100毫米为基础固化面积，模块化组件可向四个方向扩展，提供连续均匀的UV照射。由支持最多六个光源的简易控制器操作，提供365与395 nm两种波长。", "vi": "Hệ thống đóng rắn UV LED Phoseon FireJet FJ800 là giải pháp đóng rắn diện tích lớn cho ứng dụng keo dán và sơn phủ cần độ rọi thấp, thời gian lưu dài trên dây chuyền sản xuất quy mô lớn. Bắt đầu từ vùng đóng rắn cơ sở 100 mm × 100 mm, các mô-đun mở rộng theo cả bốn hướng, mang lại chiếu xạ UV liền mạch, đồng đều. Vận hành bằng bộ điều khiển đơn giản hỗ trợ tới sáu nguồn sáng, có hai bước sóng 365 và 395 nm."}, features: {"en": ["Modular and scalable: 100 mm × 100 mm base, scalable in all four directions", "Contiguous, uniform UV output across the entire curing area", "Simple controller supporting up to six light sources", "Available wavelengths: 365, 395 nm", "Air-cooled for flexible, cost-effective integration", "Optimized for large-area curing requiring low irradiance and long dwell time"], "zh": ["模块化可扩展：100毫米×100毫米基础面积，可向四个方向扩展", "整个固化区域内连续均匀的UV输出", "简易控制器，最多支持六个光源", "可选波长：365、395 nm", "风冷设计，集成灵活且经济", "针对需要低辐照度、长驻留时间的大面积固化优化"], "vi": ["Mô-đun và mở rộng được: cơ sở 100 mm × 100 mm, mở rộng theo cả bốn hướng", "Đầu ra UV liền mạch, đồng đều trên toàn vùng đóng rắn", "Bộ điều khiển đơn giản hỗ trợ tới sáu nguồn sáng", "Bước sóng có sẵn: 365, 395 nm", "Làm mát bằng khí cho tích hợp linh hoạt, tiết kiệm chi phí", "Tối ưu cho đóng rắn diện tích lớn cần độ rọi thấp và thời gian lưu dài"]}, applications: {"en": ["Micro-speaker manufacturing (adhesive curing)", "Camera module (CCM) assembly", "Flat panel display manufacturing", "Medical device assembly requiring large-area UV curing", "Large-scale electronics production lines"], "zh": ["微型扬声器制造（胶水固化）", "摄像头模组（CCM）组装", "平板显示器制造", "需要大面积UV固化的医疗器械组装", "大规模电子生产线"], "vi": ["Sản xuất loa siêu nhỏ (đóng rắn keo)", "Lắp ráp mô-đun camera (CCM)", "Sản xuất màn hình phẳng", "Lắp ráp thiết bị y tế cần đóng rắn UV diện tích lớn", "Dây chuyền sản xuất điện tử quy mô lớn"]} },
  "drf-series": { intro: {"en": "The Fusion UV DRF Series cure photoresponsive coatings, coloring inks, and ribbon matrix polymers in the production of optical fiber and cable. The DRF Series has been the UV curing system of choice for fiber manufacturing worldwide, thanks to its patented secondary elliptical reflector system that delivers highly focused, intense UV energy. The optical fiber passes through a sealed quartz tube aligned at the secondary focal point of the elliptical reflector for full-surface UV exposure. DRF systems support power levels from 1.8 kW (F300S) to 6 kW.", "zh": "Fusion UV DRF系列用于光纤与光缆生产中光敏涂层、着色油墨及带状基体聚合物的固化。凭借专利二次椭圆反射器系统提供高度聚焦的高强度UV能量，DRF系列一直是全球光纤制造的首选UV固化系统。光纤穿过密封石英管，并对准椭圆反射器的第二焦点，实现全表面UV照射。DRF系统支持1.8千瓦（F300S）至6千瓦的功率等级。", "vi": "Dòng Fusion UV DRF đóng rắn lớp phủ quang hóa, mực nhuộm màu và polymer nền băng trong sản xuất sợi quang và cáp quang. Với hệ thống gương phản xạ elip thứ cấp được cấp bằng sáng chế mang lại năng lượng UV hội tụ cao, cường độ mạnh, dòng DRF luôn là hệ thống đóng rắn UV được lựa chọn cho sản xuất sợi quang trên toàn thế giới. Sợi quang đi qua ống thạch anh kín được căn chỉnh tại tiêu điểm thứ hai của gương phản xạ elip để chiếu UV toàn bề mặt. Hệ thống DRF hỗ trợ mức công suất từ 1,8 kW (F300S) đến 6 kW."}, features: {"en": ["Patented secondary elliptical reflector: highest UV irradiance per watt", "Highly focused, intense UV energy for optical fiber curing", "Sealed quartz tube enables full-surface UV exposure with minimal stray radiation", "Noblelight microwave-powered electrodeless lamp: stable, consistent UV output", "Reaches maximum curing power within seconds of ignition", "Modular design for easy maintenance and component replacement", "Interchangeable bulbs to match spectral output to coating needs", "Optional easy-align lamp mounting system", "Optional patented back reflector for enhanced UV efficiency", "Individual lamp switching in multi-lamp setups for line-speed adjustment"], "zh": ["专利二次椭圆反射器：单位瓦数UV辐照度最高", "高度聚焦的高强度UV能量，专为光纤固化", "密封石英管实现全表面UV照射，杂散辐射极低", "Noblelight微波无极灯：UV输出稳定一致", "点亮后数秒内即达最大固化功率", "模块化设计，维护与部件更换便捷", "灯泡可更换，光谱输出可匹配涂层需求", "可选易对准灯具安装系统", "可选专利背部反射器，提升UV效率", "多灯配置下可独立开关单灯，便于调整线速"], "vi": ["Gương phản xạ elip thứ cấp được cấp bằng sáng chế: độ rọi UV trên mỗi watt cao nhất", "Năng lượng UV hội tụ cao, cường độ mạnh cho đóng rắn sợi quang", "Ống thạch anh kín cho phép chiếu UV toàn bề mặt với bức xạ tán xạ tối thiểu", "Đèn không điện cực chạy vi sóng Noblelight: đầu ra UV ổn định, nhất quán", "Đạt công suất đóng rắn tối đa trong vài giây sau khi kích hoạt", "Thiết kế mô-đun cho bảo trì và thay thế linh kiện dễ dàng", "Bóng đèn thay thế được để khớp phổ đầu ra với nhu cầu lớp phủ", "Hệ thống lắp đèn căn chỉnh dễ dàng tùy chọn", "Gương phản xạ sau được cấp bằng sáng chế tùy chọn giúp tăng hiệu suất UV", "Bật tắt từng đèn riêng trong cấu hình nhiều đèn để điều chỉnh tốc độ dây chuyền"]}, applications: {"en": ["Optical fiber coating production — photoresponsive coatings on fiber", "Coloring inks for optical fiber color coding", "Ribbon matrix polymer curing for fiber optic ribbon cable", "Draw tower UV curing systems", "Wire and cable UV coating and marking"], "zh": ["光纤涂层生产——光纤上的光敏涂层固化", "光纤色标着色油墨固化", "光纤带状光缆的带状基体聚合物固化", "拉丝塔UV固化系统", "电线电缆UV涂层与标识"], "vi": ["Sản xuất lớp phủ sợi quang — lớp phủ quang hóa trên sợi", "Mực nhuộm màu để mã hóa màu sợi quang", "Đóng rắn polymer nền băng cho cáp quang dạng băng", "Hệ thống đóng rắn UV tháp kéo sợi", "Phủ và đánh dấu UV cho dây điện, cáp"]} },
};
